    for (let test = dist[0][0]; test < 1e9; test++) {
        let ok = true;
        for (let x = 0; x < m; x++) {
            for (let y = 0; y < n; y++) {
                if (grid[x][y] === 1) {
                    for (let d = 0; d < 4; d++) {
